def parse_json(s: str):
    pos = 0

    def skip_whitespace():
        nonlocal pos
        while pos < len(s) and s[pos] in ' \t\n\r':
            pos += 1

    def parse_value():
        skip_whitespace()
        if pos >= len(s):
            raise ValueError("Unexpected end of input")
        c = s[pos]
        if c == '{':
            return parse_object()
        elif c == '[':
            return parse_array()
        elif c == '"':
            return parse_string()
        elif c == 't':
            return parse_true()
        elif c == 'f':
            return parse_false()
        elif c == 'n':
            return parse_null()
        elif c == '-' or c.isdigit():
            return parse_number()
        else:
            raise ValueError(f"Unexpected character: {c!r} at position {pos}")

    def parse_object():
        nonlocal pos
        assert s[pos] == '{'
        pos += 1
        obj = {}
        skip_whitespace()
        if pos < len(s) and s[pos] == '}':
            pos += 1
            return obj
        while True:
            skip_whitespace()
            if pos >= len(s) or s[pos] != '"':
                raise ValueError(f"Expected string key at position {pos}")
            key = parse_string()
            skip_whitespace()
            if pos >= len(s) or s[pos] != ':':
                raise ValueError(f"Expected ':' at position {pos}")
            pos += 1
            value = parse_value()
            obj[key] = value
            skip_whitespace()
            if pos >= len(s):
                raise ValueError("Unterminated object")
            if s[pos] == '}':
                pos += 1
                return obj
            elif s[pos] == ',':
                pos += 1
                skip_whitespace()
                if pos < len(s) and s[pos] == '}':
                    raise ValueError("Trailing comma in object")
            else:
                raise ValueError(f"Expected ',' or '}}' at position {pos}")

    def parse_array():
        nonlocal pos
        assert s[pos] == '['
        pos += 1
        arr = []
        skip_whitespace()
        if pos < len(s) and s[pos] == ']':
            pos += 1
            return arr
        while True:
            value = parse_value()
            arr.append(value)
            skip_whitespace()
            if pos >= len(s):
                raise ValueError("Unterminated array")
            if s[pos] == ']':
                pos += 1
                return arr
            elif s[pos] == ',':
                pos += 1
                skip_whitespace()
                if pos < len(s) and s[pos] == ']':
                    raise ValueError("Trailing comma in array")
            else:
                raise ValueError(f"Expected ',' or ']' at position {pos}")

    def parse_string():
        nonlocal pos
        assert s[pos] == '"'
        pos += 1
        result = []
        while pos < len(s):
            c = s[pos]
            if c == '"':
                pos += 1
                return ''.join(result)
            elif c == '\\':
                pos += 1
                if pos >= len(s):
                    raise ValueError("Unterminated string escape")
                e = s[pos]
                if e == '"':
                    result.append('"')
                elif e == '\\':
                    result.append('\\')
                elif e == '/':
                    result.append('/')
                elif e == 'b':
                    result.append('\b')
                elif e == 'f':
                    result.append('\f')
                elif e == 'n':
                    result.append('\n')
                elif e == 'r':
                    result.append('\r')
                elif e == 't':
                    result.append('\t')
                elif e == 'u':
                    hex_str = s[pos+1:pos+5]
                    if len(hex_str) < 4:
                        raise ValueError("Invalid unicode escape")
                    try:
                        code_point = int(hex_str, 16)
                    except ValueError:
                        raise ValueError(f"Invalid unicode escape: \\u{hex_str}")
                    # Handle surrogate pairs
                    if 0xD800 <= code_point <= 0xDBFF:
                        pos += 5
                        if pos + 1 < len(s) and s[pos] == '\\' and s[pos+1] == 'u':
                            pos += 2
                            hex_str2 = s[pos:pos+4]
                            if len(hex_str2) < 4:
                                raise ValueError("Invalid unicode escape in surrogate pair")
                            try:
                                code_point2 = int(hex_str2, 16)
                            except ValueError:
                                raise ValueError("Invalid unicode escape in surrogate pair")
                            if 0xDC00 <= code_point2 <= 0xDFFF:
                                full = 0x10000 + (code_point - 0xD800) * 0x400 + (code_point2 - 0xDC00)
                                result.append(chr(full))
                                pos += 3
                            else:
                                raise ValueError("Invalid surrogate pair")
                        else:
                            raise ValueError("Expected low surrogate")
                    else:
                        result.append(chr(code_point))
                        pos += 4
                else:
                    raise ValueError(f"Invalid escape character: {e!r}")
                pos += 1
            elif ord(c) < 0x20:
                raise ValueError(f"Invalid control character in string")
            else:
                result.append(c)
                pos += 1
        raise ValueError("Unterminated string")

    def parse_true():
        nonlocal pos
        if s[pos:pos+4] == 'true':
            pos += 4
            return True
        raise ValueError(f"Invalid token at position {pos}")

    def parse_false():
        nonlocal pos
        if s[pos:pos+5] == 'false':
            pos += 5
            return False
        raise ValueError(f"Invalid token at position {pos}")

    def parse_null():
        nonlocal pos
        if s[pos:pos+4] == 'null':
            pos += 4
            return None
        raise ValueError(f"Invalid token at position {pos}")

    def parse_number():
        nonlocal pos
        start = pos
        if pos < len(s) and s[pos] == '-':
            pos += 1
        if pos >= len(s) or not s[pos].isdigit():
            raise ValueError(f"Invalid number at position {pos}")
        if s[pos] == '0':
            pos += 1
        else:
            while pos < len(s) and s[pos].isdigit():
                pos += 1
        is_float = False
        if pos < len(s) and s[pos] == '.':
            is_float = True
            pos += 1
            if pos >= len(s) or not s[pos].isdigit():
                raise ValueError(f"Invalid number at position {pos}")
            while pos < len(s) and s[pos].isdigit():
                pos += 1
        if pos < len(s) and s[pos] in 'eE':
            is_float = True
            pos += 1
            if pos < len(s) and s[pos] in '+-':
                pos += 1
            if pos >= len(s) or not s[pos].isdigit():
                raise ValueError(f"Invalid number at position {pos}")
            while pos < len(s) and s[pos].isdigit():
                pos += 1
        num_str = s[start:pos]
        if is_float:
            return float(num_str)
        else:
            return int(num_str)

    result = parse_value()
    skip_whitespace()
    if pos != len(s):
        raise ValueError(f"Trailing characters at position {pos}")
    return result
